/**
 * In-memory catalog store, simulating a database table that an
 * upstream ERP/PIM system pushes data into during a sync.
 *
 * In production these would be database queries and a background
 * job queue; here we mutate-in-place so cache invalidation is
 * observable across page loads.
 */

let catalog = [
  { id: 'SKU-001', name: 'Laptop', price: 999.0 },
  { id: 'SKU-002', name: 'Phone', price: 699.0 },
  { id: 'SKU-003', name: 'Tablet', price: 499.0 },
  { id: 'SKU-004', name: 'Headphones', price: 199.0 },
  { id: 'SKU-005', name: 'Watch', price: 299.0 },
]

let lastSyncedAt = new Date().toISOString().slice(0, 16).replace('T', ' at ')
let syncGeneration = 0

/**
 * Returns all products from the catalog store.
 * The simulated 100 ms delay represents a typical database read.
 */
export async function getAllProducts() {
  await new Promise((resolve) => setTimeout(resolve, 100))
  return catalog.map((p) => ({ ...p }))
}

/**
 * Simulates an upstream ERP/PIM sync that may take several seconds
 * (mirroring a real job that processes thousands of SKUs).
 *
 * On each call it refreshes prices by a small random delta so the
 * effect of cache invalidation is visible to the demo user.
 */
export async function syncProductsFromERP() {
  // Simulate the latency of a bulk sync for thousands of SKUs
  await new Promise((resolve) => setTimeout(resolve, 4000))

  syncGeneration++

  // "New data from upstream" — adjust each price by a small delta
  // so the refresh is visually observable after revalidation.
  const deltas = [5, -3, 2, -1, 8]
  catalog = catalog.map((p, i) => ({
    ...p,
    price: Math.round((p.price + (deltas[i % deltas.length] ?? 0)) * 100) / 100,
  }))

  lastSyncedAt = new Date().toISOString().slice(0, 16).replace('T', ' at ')

  console.log(
    `[db] ERP/PIM sync complete (generation ${syncGeneration}) — ` +
      `${catalog.length} products updated at ${lastSyncedAt}`
  )
}

/**
 * Returns metadata about the last sync (for diagnostics / admin UI).
 */
export async function getSyncMetadata() {
  return {
    generation: syncGeneration,
    lastSyncedAt,
    productCount: catalog.length,
  }
}

